// ============================================================
// WF04 — Validate incoming reservation payload
// ============================================================

const body = $('Webhook Trigger').item.json.body;

const required = ['property_id', 'check_in', 'check_out'];
const missing = required.filter(field => !body[field]);

if (missing.length > 0) {
  throw new Error(`Champs requis manquants: ${missing.join(', ')}`);
}

// Validation format dates
const dateRegex = /^\d{4}-\d{2}-\d{2}$/;
if (!dateRegex.test(body.check_in)) {
  throw new Error(`Format check_in invalide: ${body.check_in} (attendu: YYYY-MM-DD)`);
}
if (!dateRegex.test(body.check_out)) {
  throw new Error(`Format check_out invalide: ${body.check_out} (attendu: YYYY-MM-DD)`);
}

// Validation check_out > check_in
if (new Date(body.check_out) <= new Date(body.check_in)) {
  throw new Error(`check_out (${body.check_out}) doit etre apres check_in (${body.check_in})`);
}

return [{
  json: {
    reservation_id: body.id || null,
    property_id: body.property_id,
    check_in: body.check_in,
    check_out: body.check_out,
    nb_guests: body.nb_guests || 1,
    guest_name: body.guest_name || 'Voyageur',
    check_in_time: body.check_in_time || null,
    check_out_time: body.check_out_time || null
  }
}];

// ============================================================
// WF04 — Create cleaning tasks (checkout_clean + checkin_prep + check_in_greeting)
// + checklist items from property templates or defaults
// ============================================================

const config = $('Config').item.json;
const reservation = $('Code: Validate').item.json;
const propertyArr = $('Supabase: Get Property').all().map(i => i.json);
const property = Array.isArray(propertyArr[0]) ? propertyArr[0][0] : propertyArr[0];

const supabaseUrl = config.SUPABASE_URL;
const supabaseKey = config.SUPABASE_SERVICE_KEY;

const headers = {
  'apikey': supabaseKey,
  'Authorization': `Bearer ${supabaseKey}`,
  'Content-Type': 'application/json',
  'Prefer': 'return=representation'
};

// --- Default checklists ---
const defaultCheckoutChecklist = [
  'Vider les poubelles',
  'Faire la vaisselle',
  'Changer les draps',
  'Nettoyer la salle de bain',
  'Passer l\'aspirateur',
  'Laver les sols',
  'Sortir les poubelles',
  'Nettoyer les surfaces',
  'Reapprovisionner (savon, papier toilette)',
  'Verifier objets oublies'
];

const defaultCheckinChecklist = [
  'Verifier que le menage checkout a ete effectue',
  'Verifier l\'etat general du logement',
  'Verifier les fournitures (draps, serviettes)',
  'Regler chauffage/climatisation',
  'Verifier cles/digicode',
  'Tester WiFi'
];

const defaultGreetingChecklist = [
  { label: 'Accueillir le voyageur a l\'heure prevue', position: 1 },
  { label: 'Faire la visite guidee du logement', position: 2 },
  { label: 'Remettre les cles / expliquer le digicode', position: 3 },
  { label: 'Montrer les equipements (chauffage, WiFi, electromenager)', position: 4 },
  { label: 'Donner le livret d\'accueil (papier ou QR code)', position: 5 }
];

// --- Get property checklists from Supabase node ---
let checkoutItems = defaultCheckoutChecklist;
let checkinItems = defaultCheckinChecklist;
const checklists = $('Supabase: Get Property Checklists').all().map(i => i.json);

const checkoutTemplate = checklists.find(c => c.type === 'checkout_clean');
const checkinTemplate = checklists.find(c => c.type === 'checkin_prep');

if (checkoutTemplate && checkoutTemplate.items && checkoutTemplate.items.length > 0) {
  checkoutItems = checkoutTemplate.items;
}
if (checkinTemplate && checkinTemplate.items && checkinTemplate.items.length > 0) {
  checkinItems = checkinTemplate.items;
}

// --- Calculate scheduled times ---
const checkOutTime = reservation.check_out_time || '11:00';
const checkInTime = reservation.check_in_time || '16:00';

// checkin_prep = check_in_time - 2h (minimum 10:00)
let prepHour = parseInt(checkInTime.split(':')[0]) - 2;
if (prepHour < 10) prepHour = 10;
const checkinPrepTime = String(prepHour).padStart(2, '0') + ':00';

const tasksCreated = [];

// --- 1. Create checkout_clean task ---
const checkoutTask = {
  property_id: reservation.property_id,
  reservation_id: reservation.reservation_id,
  type: 'checkout_clean',
  status: 'pending',
  scheduled_date: reservation.check_out,
  scheduled_time: checkOutTime,
  notes: `Depart de ${reservation.guest_name} (${reservation.nb_guests} pers.)`
};

const checkoutRes = await fetch(
  `${supabaseUrl}/rest/v1/cleaning_tasks`,
  {
    method: 'POST',
    headers,
    body: JSON.stringify(checkoutTask)
  }
);
const checkoutCreated = await checkoutRes.json();
const checkoutId = Array.isArray(checkoutCreated) ? checkoutCreated[0].id : checkoutCreated.id;
tasksCreated.push({ id: checkoutId, type: 'checkout_clean', date: reservation.check_out });

// Create checkout checklist items
const checkoutChecklistItems = checkoutItems.map((label, idx) => ({
  task_id: checkoutId,
  label: label,
  position: idx + 1,
  is_completed: false
}));

await fetch(
  `${supabaseUrl}/rest/v1/task_checklist_items`,
  {
    method: 'POST',
    headers,
    body: JSON.stringify(checkoutChecklistItems)
  }
);

// --- 2. Create check_in_greeting task (if property has staff_checkin) ---
if (property.check_in_mode === 'staff_checkin') {
  const greetingTime = reservation.check_in_time || '16:00';

  let greetingItems = defaultGreetingChecklist;
  try {
    const greetingTemplate = checklists.find(c => c.type === 'check_in_greeting');
    if (greetingTemplate && greetingTemplate.items && greetingTemplate.items.length > 0) {
      greetingItems = greetingTemplate.items;
    }
  } catch (err) {
    // Use defaults
  }

  const greetingTask = {
    property_id: reservation.property_id,
    reservation_id: reservation.reservation_id,
    type: 'check_in_greeting',
    status: 'pending',
    scheduled_date: reservation.check_in,
    scheduled_time: greetingTime,
    notes: `Accueil de ${reservation.guest_name} (${reservation.nb_guests} pers.) prevu a ${greetingTime}`
  };

  const greetingRes = await fetch(
    `${supabaseUrl}/rest/v1/cleaning_tasks`,
    {
      method: 'POST',
      headers,
      body: JSON.stringify(greetingTask)
    }
  );
  const greetingCreated = await greetingRes.json();
  const greetingId = Array.isArray(greetingCreated) ? greetingCreated[0].id : greetingCreated.id;
  tasksCreated.push({ id: greetingId, type: 'check_in_greeting', date: reservation.check_in });

  const greetingChecklistItems = greetingItems.map((item, idx) => ({
    task_id: greetingId,
    label: typeof item === 'string' ? item : item.label,
    position: typeof item === 'string' ? idx + 1 : item.position,
    is_completed: false
  }));

  await fetch(
    `${supabaseUrl}/rest/v1/task_checklist_items`,
    {
      method: 'POST',
      headers,
      body: JSON.stringify(greetingChecklistItems)
    }
  );
}

// --- 3. Create checkin_prep task (if check_in != check_out) ---
if (reservation.check_in !== reservation.check_out) {
  const checkinTask = {
    property_id: reservation.property_id,
    reservation_id: reservation.reservation_id,
    type: 'checkin_prep',
    status: 'pending',
    scheduled_date: reservation.check_in,
    scheduled_time: checkinPrepTime,
    notes: `Arrivee de ${reservation.guest_name} (${reservation.nb_guests} pers.) prevue a ${checkInTime}`
  };

  const checkinRes = await fetch(
    `${supabaseUrl}/rest/v1/cleaning_tasks`,
    {
      method: 'POST',
      headers,
      body: JSON.stringify(checkinTask)
    }
  );
  const checkinCreated = await checkinRes.json();
  const checkinId = Array.isArray(checkinCreated) ? checkinCreated[0].id : checkinCreated.id;
  tasksCreated.push({ id: checkinId, type: 'checkin_prep', date: reservation.check_in });

  // Create checkin checklist items
  const checkinChecklistItems = checkinItems.map((label, idx) => ({
    task_id: checkinId,
    label: label,
    position: idx + 1,
    is_completed: false
  }));

  await fetch(
    `${supabaseUrl}/rest/v1/task_checklist_items`,
    {
      method: 'POST',
      headers,
      body: JSON.stringify(checkinChecklistItems)
    }
  );
}

return [{
  json: {
    reservation_id: reservation.reservation_id,
    property_id: reservation.property_id,
    property_name: property.name,
    property_address: property.address,
    owner_id: property.owner_id,
    guest_name: reservation.guest_name,
    nb_guests: reservation.nb_guests,
    check_in: reservation.check_in,
    check_out: reservation.check_out,
    tasks_created: tasksCreated,
    tasks_count: tasksCreated.length
  }
}];

// ============================================================
// WF04 — Round-robin staff assignment
// Assigner au staff avec le moins de taches cette semaine
// ============================================================

const config = $('Config').item.json;
const taskData = $('Code: Create Tasks').item.json;
const staffArr = $('Supabase: Get Available Staff').all().map(i => i.json);
const staffList = Array.isArray(staffArr[0]) ? staffArr[0] : staffArr;

if (!staffList || staffList.length === 0) {
  // Pas de staff disponible — taches creees mais non assignees
  return [{
    json: {
      ...taskData,
      assignments: [],
      no_staff_available: true
    }
  }];
}

const supabaseUrl = config.SUPABASE_URL;
const supabaseKey = config.SUPABASE_SERVICE_KEY;
const headers = {
  'apikey': supabaseKey,
  'Authorization': `Bearer ${supabaseKey}`,
  'Content-Type': 'application/json'
};

// --- Compter les taches par staff cette semaine ---
const now = new Date();
const monday = new Date(now);
monday.setDate(now.getDate() - now.getDay() + 1);
const sunday = new Date(monday);
sunday.setDate(monday.getDate() + 6);

const mondayStr = monday.toISOString().slice(0, 10);
const sundayStr = sunday.toISOString().slice(0, 10);

const staffIds = staffList.map(s => s.id);
const staffIdsFilter = staffIds.map(id => `"${id}"`).join(',');

let taskCounts = {};
try {
  const countRes = await fetch(
    `${supabaseUrl}/rest/v1/cleaning_tasks?assigned_to=in.(${staffIdsFilter})&scheduled_date=gte.${mondayStr}&scheduled_date=lte.${sundayStr}&select=assigned_to`,
    { headers }
  );
  const weekTasks = await countRes.json();

  for (const t of weekTasks) {
    taskCounts[t.assigned_to] = (taskCounts[t.assigned_to] || 0) + 1;
  }
} catch (err) {
  // If count fails, use empty counts (all staff equal)
}

// --- Assigner chaque tache au staff avec le moins de taches ---
const assignments = [];

for (const task of taskData.tasks_created) {
  // Trouver le staff avec le moins de taches
  let minCount = Infinity;
  let candidates = [];

  for (const staff of staffList) {
    const count = taskCounts[staff.id] || 0;
    if (count < minCount) {
      minCount = count;
      candidates = [staff];
    } else if (count === minCount) {
      candidates.push(staff);
    }
  }

  // Si egalite, choix aleatoire
  const chosen = candidates[Math.floor(Math.random() * candidates.length)];

  // Update la tache en base
  try {
    await fetch(
      `${supabaseUrl}/rest/v1/cleaning_tasks?id=eq.${task.id}`,
      {
        method: 'PATCH',
        headers: { ...headers, 'Prefer': 'return=representation' },
        body: JSON.stringify({ assigned_to: chosen.id })
      }
    );
  } catch (err) {
    // Assignment failed — task remains unassigned
  }

  // Incrementer le compteur pour le prochain tour
  taskCounts[chosen.id] = (taskCounts[chosen.id] || 0) + 1;

  assignments.push({
    task_id: task.id,
    task_type: task.type,
    task_date: task.date,
    staff_id: chosen.id,
    staff_name: chosen.display_name,
    staff_email: chosen.email
  });
}

return [{
  json: {
    ...taskData,
    assignments: assignments,
    no_staff_available: false
  }
}];

// ============================================================
// WF04 — Build notification emails for assigned staff
// ============================================================

const config = $('Config').item.json;
const data = $input.item.json;

if (data.no_staff_available || !data.assignments || data.assignments.length === 0) {
  return [{ json: { emails: [], warning: 'Pas de staff assigne — pas d\'email a envoyer' } }];
}

const typeLabels = {
  'checkout_clean': 'Menage depart',
  'checkin_prep': 'Preparation arrivee',
  'check_in_greeting': 'Accueil voyageur',
  'ad_hoc': 'Tache ponctuelle'
};

const emails = [];

// Regrouper par staff (un staff peut avoir 2 taches pour la meme reservation)
const staffEmails = {};

for (const assignment of data.assignments) {
  if (!assignment.staff_email) continue;

  if (!staffEmails[assignment.staff_email]) {
    staffEmails[assignment.staff_email] = {
      to: assignment.staff_email,
      staffName: assignment.staff_name,
      tasks: []
    };
  }

  staffEmails[assignment.staff_email].tasks.push(assignment);
}

for (const [email, staffData] of Object.entries(staffEmails)) {
  const firstName = staffData.staffName.split(' ')[0];
  const taskCount = staffData.tasks.length;

  let html = '<div style="font-family:-apple-system,sans-serif;max-width:600px;margin:0 auto;">';
  html += '<div style="background:#1a1a2e;color:#fff;padding:16px;border-radius:8px 8px 0 0;">';
  html += `<h2 style="margin:0;">Nouvelle tache assignee</h2>`;
  html += '</div>';
  html += '<div style="padding:16px;background:#f9fafb;border:1px solid #e5e7eb;border-top:none;border-radius:0 0 8px 8px;">';
  html += `<p>Bonjour ${firstName},</p>`;
  html += `<p>Vous avez ${taskCount} nouvelle(s) tache(s) pour le bien <strong>${data.property_name}</strong>.</p>`;

  let dateFR = '';
  for (const task of staffData.tasks) {
    const typeLabel = typeLabels[task.task_type] || task.task_type;
    const dateObj = new Date(task.task_date + 'T12:00:00');
    dateFR = dateObj.toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long' });

    html += '<div style="margin:12px 0;padding:12px;background:#fff;border-radius:6px;border-left:4px solid #6366f1;">';
    html += `<h3 style="margin:0 0 8px 0;color:#1a1a2e;">${typeLabel}</h3>`;
    html += `<p style="margin:4px 0;"><strong>Date :</strong> ${dateFR}</p>`;
    html += `<p style="margin:4px 0;"><strong>Bien :</strong> ${data.property_name}</p>`;
    html += `<p style="margin:4px 0;"><strong>Adresse :</strong> <a href="https://maps.google.com/?q=${encodeURIComponent(data.property_address)}">${data.property_address}</a></p>`;
    html += `<p style="margin:4px 0;"><strong>Voyageur :</strong> ${data.guest_name} (${data.nb_guests} pers.)</p>`;
    html += '</div>';
  }

  html += `<p style="margin-top:16px;"><a href="${config.DASHBOARD_URL}/planning" style="display:inline-block;background:#6366f1;color:#fff;padding:10px 20px;border-radius:6px;text-decoration:none;">Voir mon planning</a></p>`;
  html += '</div></div>';

  emails.push({
    json: {
      to: email,
      subject: `[Neurolia-Immo] Nouvelle tache \u2014 ${data.property_name} (${dateFR})`,
      html: html,
      staffName: staffData.staffName
    }
  });
}

return emails.length > 0 ? emails : [{ json: { emails: [], warning: 'Aucun email a envoyer' } }];
